def compute_score() -> tuple[str, float]:
    # Try to identify the title from Slide 1
    from pptx import Presentation
    import re

    prs = Presentation(modified_ppt_path)
    slide = prs.slides[0]
    expected_title = 'Literature and Human Experiences The Common Module'
    found = False
    for shape in slide.shapes:
        if shape.has_text_frame:
            text = shape.text_frame.text.strip()
            # Normalize whitespace
            text_norm = re.sub(r'\s+', ' ', text)
            if text_norm == expected_title:
                found = True
                break
    if found:
        return ("Title matches exactly as requested.", 1.0)
    else:
        return ("Title does not exactly match the requested text.", 0.0)

