def compute_score() -> tuple[str, float]:
    # Only allow modifications to the title shape on the first slide
    if not ppt_diff.modified_slides:
        return ("No slides were modified.", 1.0)
    # For any modified slide, ensure it's slide 1 and only the title shape was changed
    from pptx import Presentation
    orig = Presentation(original_ppt_path)
    mod = Presentation(modified_ppt_path)
    # Get title text on slide 1 before and after
    orig_slide = orig.slides[0]
    mod_slide = mod.slides[0]
    orig_titles = set()
    mod_titles = set()
    for shape in orig_slide.shapes:
        if shape.has_text_frame:
            orig_titles.add(shape.text_frame.text.strip())
    for shape in mod_slide.shapes:
        if shape.has_text_frame:
            mod_titles.add(shape.text_frame.text.strip())
    modified_slides_ok = True
    for (before, after) in ppt_diff.modified_slides:
        if before.slide_number != 1:
            modified_slides_ok = False
            break
    if not modified_slides_ok:
        return ("Slides other than the title slide were modified.", 0.0)
    # If only title text changed, that's ok
    # For simplicity, we assume only the title change is allowed on slide 1
    if orig_titles != mod_titles:
        # Check that the only difference is the title string
        # Allow exactly one differing element between equal-length collections
        # Using symmetric difference on sets: replacing one element yields diff size == 2
        symmetric_diff_count = len(orig_titles ^ mod_titles)
        if len(orig_titles) == len(mod_titles) and symmetric_diff_count == 2:
            return ("Only the title text on slide 1 was changed.", 1.0)
        else:
            return (f"Multiple text elements changed on slide 1.", 0.0)
    return ("No content changed except the title.", 1.0)

